import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Sidebar = ({ active }) => {
  const navigate = useNavigate();
  const { logout } = useAuth();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const menuItems = [
    { label: 'Dashboard', path: '/dashboard', icon: '📊' },
    { label: 'Customers', path: '/customers', icon: '👥' },
    { label: 'Orders', path: '/orders', icon: '📦' },
    { label: 'Analytics', path: '/analytics', icon: '📈' },
    { label: 'Segments', path: '/segments', icon: '🎯' },
    { label: 'Templates', path: '/templates', icon: '📝' },
    { label: 'Campaigns', path: '/campaigns', icon: '📧' },
    { label: 'AI Campaigns', path: '/ai-campaigns', icon: '🤖' },
    { label: 'Insights', path: '/insights', icon: '🧠' },
    { label: 'AI Builder', path: '/ai-segments', icon: '✨' },
  ];

  return (
    <div className="bg-gray-800 text-white w-64 min-h-screen p-4">
      <h1 className="text-2xl font-bold mb-8">AI-CRM</h1>
      <nav className="space-y-2">
        {menuItems.map((item) => (
          <button
            key={item.path}
            onClick={() => navigate(item.path)}
            className={`w-full text-left px-4 py-2 rounded transition ${
              active === item.path
                ? 'bg-blue-600 text-white'
                : 'text-gray-300 hover:bg-gray-700'
            }`}
          >
            {item.icon} {item.label}
          </button>
        ))}
      </nav>
      <button
        onClick={handleLogout}
        className="w-full mt-8 bg-red-600 hover:bg-red-700 px-4 py-2 rounded transition text-white"
      >
        Logout
      </button>
    </div>
  );
};

export default Sidebar;
